#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

void backtrack(int **matrix, int *chosen, int *columns, int row, int n, int *result, int *resultSize) {
    if (row == n) {
        int xor = 0;
        for (int i = 0; i < n; i++) {
            xor ^= matrix[i][chosen[i]];
        }
        result[(*resultSize)++] = xor;
        return;
    }
    for (int col = 0; col < n; col++) {
        if (columns[col] == 0) {
            chosen[row] = col;
            columns[col] = 1;
            backtrack(matrix, chosen, columns, row + 1, n, result, resultSize);
            columns[col] = 0;
        }
    }
}

int* chefAndLostStory(int **matrix, int n, int *returnSize) {
    int *result = (int*)malloc(n * n * sizeof(int));
    *returnSize = 0;
    int *chosen = (int*)malloc(n * sizeof(int));
    int *columns = (int*)malloc(n * sizeof(int));
    for (int i = 0; i < n; i++) {
        columns[i] = 0;
    }
    backtrack(matrix, chosen, columns, 0, n, result, returnSize);
    qsort(result, *returnSize, sizeof(int), compare);
    return result;
}

